#include <iostream>

class Base {
public:
    int getValue() const { return m_val; }
    void setValue(int v) { m_val = v; }
protected:
    int m_val{};
};

class ReadOnly : public Base {
    using Base::setValue;

public:
    ReadOnly(int v)
    {
        setValue(v);
    }

    void reset(int v)
    {
        setValue(v);
    }
};

int main()
{
    int initial{};
    int resetVal{};
    std::cin >> initial >> resetVal;

    ReadOnly ro{ initial };
    std::cout << "initial: " << ro.getValue() << '\n';

    ro.reset(resetVal);
    std::cout << "reset: " << ro.getValue() << '\n';

    Base& baseRef{ ro };
    std::cout << "base ref: " << baseRef.getValue() << '\n';

    return 0;
}

